// Generates card variants for each topic. Each topic has 50+ unique cards.
// Cards are built from template arrays and combined programmatically.
// All content is original. This app is not affiliated with AA World Services, Inc.

const BB_CARDS = [
  { sub: 'Chapter 1 — A Founder\'s Story', sum: 'The co-founder of modern twelve-step recovery shares his journey from hopeless addiction to a life of purpose, illustrating the progression of the disease and the spiritual change that made recovery possible.', q: '"The most important thing is not where we came from, but where we are going — and that we do not have to go there alone."', tags: ['Chapter 1', 'Founders'] },
  { sub: 'Chapter 2 — There Is a Solution', sum: 'The solution lies in a spiritual experience. This chapter explains what addiction really is and why only a profound change in consciousness can relieve it.', q: '"The turning point comes when we stop trying to manage the problem and start allowing something greater to manage us."', tags: ['Chapter 2', 'Solution'] },
  { sub: 'Chapter 3 — The Mental Obsession', sum: 'This discussion demolishes the idea that a true addict can ever drink normally again. It presents compelling examples of the mental obsession that precedes every relapse.', q: '"The belief that we can someday drink like normal people is the single most dangerous lie addiction tells us."', tags: ['Chapter 3', 'Obsession'] },
  { sub: 'Chapter 4 — For the Skeptic', sum: 'This chapter speaks to those who struggle with the concept of God, suggesting an open mind and willingness to believe in a power greater than ourselves is all that is required.', q: '"All that is required to begin is the willingness to believe that something greater than our own thinking might help."', tags: ['Chapter 4', 'Higher Power'] },
  { sub: 'Chapter 5 — How It Works', sum: 'Those who thoroughly follow the path of recovery rarely fail. This chapter lays out the twelve steps and emphasizes rigorous honesty as the foundation.', q: '"Addiction is cunning, baffling, and powerful — but the program, honestly worked, is more powerful still."', tags: ['Chapter 5', 'Steps'] },
  { sub: 'Chapter 6 — Into Action', sum: 'Steps 5 through 9 in practical detail. Action, not just understanding, produces results. A faith that is not lived is not a faith at all.', q: '"Understanding the steps is not enough — we have to take them, and keep taking them, one day at a time."', tags: ['Chapter 6', 'Action'] },
  { sub: 'Chapter 7 — Working With Others', sum: 'Nothing ensures immunity from drinking like intensive work with other addicts. This chapter teaches how to carry the message of recovery effectively.', q: '"Our own recovery depends on helping others find theirs — this is not charity, it is necessity."', tags: ['Chapter 7', 'Service'] },
  { sub: 'Chapter 8 — The Family and Recovery', sum: 'Acknowledges the suffering addiction inflicts on loved ones and offers guidance for patience, understanding, and family recovery together.', q: '"Recovery changes not just the person who was suffering, but everyone around them — if they let it."', tags: ['Chapter 8', 'Family'] },
  { sub: 'Chapter 9 — The Family Afterward', sum: 'Recovery brings changes the whole family must adjust to. Rebuilding trust and family life requires patience and humility from everyone involved.', q: '"Those of us who have found our way out of addiction owe something to those still looking for the door."', tags: ['Chapter 9', 'Family'] },
  { sub: 'Chapter 10 — To Employers', sum: 'Addiction is a disease, not a moral failing. A person in solid recovery may become an organization\'s most committed and reliable contributor.', q: '"Someone who has faced the depths of addiction and come back has a strength most people never have to develop."', tags: ['Chapter 10', 'Work'] },
  { sub: 'Chapter 11 — A Vision for You', sum: 'A hopeful picture of what life can be like in recovery and the community of healing that awaits anyone willing to reach for it.', q: '"The life that waits on the other side of surrender is more than most of us ever dared to imagine."', tags: ['Chapter 11', 'Hope'] },
  { sub: 'The Medical Perspective', sum: 'Addiction involves both a physical component and a mental obsession. A profound inner change is necessary for lasting recovery.', q: '"We could not simply think our way into recovery. The change had to happen at a deeper level than thought."', tags: ['Medical', 'Disease'] },
  { sub: 'The Promises of Recovery', sum: 'Working the first nine steps brings tangible gifts: new freedom, new happiness, peace, and the ability to help others who are still suffering.', q: '"Recovery gives back far more than addiction ever took — but we have to do the work to receive those gifts."', tags: ['Promises', 'Hope'] },
  { sub: 'Acceptance as a Daily Practice', sum: 'Acceptance is the answer to so many of life\'s problems. When we stop fighting reality, serenity becomes possible in any circumstance.', q: '"We cannot change what we refuse to accept — and we cannot accept what we are still pretending is not real."', tags: ['Acceptance', 'Serenity'] },
  { sub: 'Freedom from Resentment', sum: 'Praying for those we resent sets us free. Learning to release resentment is one of the most transformative practices in recovery.', q: '"Holding onto resentment is choosing to let someone else live rent-free in your head."', tags: ['Resentment', 'Freedom'] },
  { sub: 'Step 3 — Surrender Prayer', sum: 'A surrendering of self-will. This practice marks the turning point from self-reliance to trust in a power greater than ourselves.', q: '"We cannot simultaneously grip control with both hands and ask a Higher Power to guide us. We have to let go first."', tags: ['Step 3', 'Prayer'] },
  { sub: 'Step 7 — Asking for Change', sum: 'Humbly asking a Higher Power to remove our shortcomings so we can better serve others. A practice of surrender and trust.', q: '"We do not ask to become perfect — only to become useful, and to stop causing harm."', tags: ['Step 7', 'Prayer'] },
  { sub: 'Step 4 — The Resentment Inventory', sum: 'Examining resentments is the core of Step 4. Listing who, why, and what our part was brings clarity and eventually freedom.', q: '"Resentment is a primary threat to lasting sobriety — it poisons from within."', tags: ['Step 4', 'Resentment'] },
  { sub: 'Step 4 — The Fear Inventory', sum: 'By identifying and sharing our fears, we begin to trust that something greater than ourselves can handle what we cannot.', q: '"Fear has driven most of our destructive behavior. Naming it is the first step toward releasing it."', tags: ['Step 4', 'Fear'] },
  { sub: 'Daily Reprieve', sum: 'Our sobriety depends on maintaining our spiritual condition each day. We are not permanently cured — we live in a daily state of grace.', q: '"Recovery is not something we achieve and then own. It is something we maintain — one day at a time."', tags: ['Daily Reprieve', 'Maintenance'] },
  { sub: 'Emotional Sobriety', sum: 'Beyond physical sobriety lies emotional sobriety — the ability to handle life\'s ups and downs without being overwhelmed or reaching for a substance.', q: '"Physical sobriety was just the beginning. Emotional sobriety is the ongoing work of becoming a whole person."', tags: ['Emotional Sobriety', 'Growth'] },
  { sub: 'Principles Before Personalities', sum: 'Recovery calls us to place principles above personalities. The message matters more than the person carrying it.', q: '"No individual person is more important than the principles that keep us all well."', tags: ['Principles', 'Anonymity'] },
  { sub: 'Personal Stories — Identification', sum: 'Shared experience is the bedrock of recovery. Every story carries a common thread — hope. The details differ, but the feelings are the same.', q: '"We recover in community by recognizing ourselves in each other\'s stories."', tags: ['Stories', 'Identification'] },
  { sub: 'Relationship Inventory', sum: 'Examining where our behavior has been selfish, dishonest, or harmful in relationships — about honesty, not shame.', q: '"The most important relationship question in recovery is always the same: what was my part?"', tags: ['Step 4', 'Relationships'] },
  { sub: 'Step 4 — Searching Moral Inventory', sum: 'A thorough and honest look at ourselves. Writing reveals patterns of behavior that have caused harm and kept us stuck.', q: '"Writing it down makes it real. We cannot quietly revise our inventory when it becomes uncomfortable."', tags: ['Step 4', 'Inventory'] },
  { sub: 'Steps 8 and 9 — Making Amends', sum: 'We list those we have harmed and become willing to make amends. Direct amends wherever possible, except when doing so would injure others.', q: '"Making amends is not about what we feel — it is about what we owe. Courage gets us started."', tags: ['Steps 8-9', 'Amends'] },
  { sub: 'Step 10 — Continued Inventory', sum: 'The maintenance step. By continuing to take personal inventory and promptly admitting when we are wrong, we keep our side of the street clean.', q: '"We watch for selfishness, dishonesty, resentment, and fear — not because we are failures, but because we are human."', tags: ['Step 10', 'Maintenance'] },
  { sub: 'Step 11 — Prayer and Meditation', sum: 'Deepening conscious contact with a Higher Power through prayer and meditation. The spiritual practice that sustains long-term recovery.', q: '"Prayer is how we talk. Meditation is how we listen. Both are needed."', tags: ['Step 11', 'Meditation'] },
  { sub: 'Step 12 — Carrying the Message', sum: 'Having had a spiritual awakening as a result of these steps, we carry this message to others and practice these principles in all our affairs.', q: '"We protect our own sobriety by helping others find theirs — this is the final gift the steps give us."', tags: ['Step 12', 'Service'] },
  { sub: 'Powerlessness Over People', sum: 'Recovery extends beyond alcohol. We are powerless over people, places, and things. Accepting this brings lasting peace.', q: '"Control is the illusion that fed our addiction. Acceptance is the truth that sets us free."', tags: ['Step 1', 'Powerlessness'] },
];

const REFL_CARDS = [
  { sub: 'New Beginnings', sum: 'Each new day brings opportunity to renew our commitment to recovery, reflect on growth, and set intentions grounded in what we have learned.', q: '"Every morning is a new chance to show up differently than we did yesterday."', tags: ['New Beginnings', 'Gratitude'] },
  { sub: 'Letting Go of Control', sum: 'Our need to control creates suffering. Letting go is trusting that a power greater than ourselves is at work, even when we cannot see it.', q: '"We held on so tightly to how things had to be that we missed how good things could have been."', tags: ['Control', 'Surrender'] },
  { sub: 'Living in the Present', sum: 'Anxiety comes from the future; depression from the past. Recovery teaches us to live in the only moment we truly have — now.', q: '"The past is a memory and the future is a plan. The present is the only place where recovery actually happens."', tags: ['Present Moment', 'Mindfulness'] },
  { sub: 'Dealing with Anger', sum: 'Anger is natural but can threaten sobriety when left unaddressed. Learning to process it without acting out is essential to lasting recovery.', q: '"Anger tells us something true about ourselves — what we do with that information is what matters."', tags: ['Anger', 'Emotions'] },
  { sub: 'Gratitude Practice', sum: 'Gratitude is the antidote to self-pity, resentment, and fear. A daily gratitude practice genuinely transforms our outlook.', q: '"It is impossible to feel grateful and sorry for yourself at the same time. Choose gratitude."', tags: ['Gratitude', 'Practice'] },
  { sub: 'Self-Pity and Its Cure', sum: 'Self-pity isolates us and can lead back to drinking. The cure is action — getting outside ourselves through service and connection.', q: '"Self-pity is a trap that looks like a resting place. The only way out is through."', tags: ['Self-Pity', 'Service'] },
  { sub: 'Acceptance in Practice', sum: 'Learning to distinguish what we can and cannot change is the practical heart of lasting peace in recovery.', q: '"Accepting what we cannot change is not giving up — it is putting our energy where it can actually do some good."', tags: ['Acceptance', 'Serenity'] },
  { sub: 'Loneliness in Recovery', sum: 'Loneliness is common in early recovery, but the fellowship offers a genuine remedy. We are never as alone as we feel.', q: '"Recovery communities are not just groups — they are proof that we were never as alone as addiction told us we were."', tags: ['Loneliness', 'Fellowship'] },
  { sub: 'Expectations vs. Reality', sum: 'Unmet expectations are the seeds of resentment. Releasing expectations opens us to what life actually has to offer.', q: '"Expectations are invitations for disappointment. Openness is the antidote."', tags: ['Expectations', 'Acceptance'] },
  { sub: 'Trusting the Process', sum: 'Recovery is not a straight line. Trusting the process means believing the work pays off even when we cannot yet see how.', q: '"We did not get sick overnight, and we will not get well overnight. Trust the process."', tags: ['Trust', 'Faith'] },
  { sub: 'Patience in Recovery', sum: 'We want results immediately, but genuine growth takes time. Patience with ourselves and others is itself a spiritual practice.', q: '"More will be revealed — and it always is, to those who stay and keep doing the work."', tags: ['Patience', 'Growth'] },
  { sub: 'Honesty with Self', sum: 'Self-deception kept us sick. Honest self-appraisal is the foundation of all spiritual progress in recovery.', q: '"The most important conversation in recovery is the one you have with yourself when no one is watching."', tags: ['Honesty', 'Self-Awareness'] },
  { sub: 'Forgiveness', sum: 'Forgiving others — and ourselves — frees us from the prison of resentment. Forgiveness does not mean condoning the harm.', q: '"Holding onto resentment keeps us chained to the past. Forgiveness is freedom — not for them, but for us."', tags: ['Forgiveness', 'Resentment'] },
  { sub: 'Service as Medicine', sum: 'When we are of service to others, our own problems shrink. Helping someone else is one of the most reliable tools in recovery.', q: '"The fastest way out of our own head is to walk into someone else\'s pain and try to help."', tags: ['Service', 'Action'] },
  { sub: 'Courage to Change', sum: 'Change requires courage — the courage to face our fears, admit our wrongs, and step into the unknown trusting we will be okay.', q: '"Courage is not the absence of fear. It is taking the next step anyway."', tags: ['Courage', 'Change'] },
  { sub: 'Finding Your Higher Power', sum: 'A higher power can be anything genuinely greater than ourselves. The journey to find one is deeply personal and ongoing.', q: '"The only requirement for a Higher Power is that it be more reliable than our own best thinking got us."', tags: ['Higher Power', 'Faith'] },
  { sub: 'Humility vs. Pride', sum: 'Pride keeps us stuck; humility opens doors. True humility is simply seeing ourselves as we really are — no more, no less.', q: '"Pride tells us we are the exception. Humility reminds us we are not — and that is actually a relief."', tags: ['Humility', 'Pride'] },
  { sub: 'Dealing with Loss', sum: 'Loss is part of life. In recovery, we learn to grieve without drinking and find strength in our community and our faith.', q: '"We do not have to drink over grief. Feeling it, sharing it, and moving through it is possible — and it heals."', tags: ['Loss', 'Grief'] },
  { sub: 'Relationships in Recovery', sum: 'Recovery transforms our relationships. We learn to be honest, vulnerable, and present with the people we love.', q: '"Recovery does not just change us — it changes how we show up for everyone around us."', tags: ['Relationships', 'Growth'] },
  { sub: 'Fear of the Future', sum: 'Fear of what might happen robs us of today. Recovery teaches us to trust that we will be given what we need, when we need it.', q: '"Most of what we feared never happened. And everything that did, we survived — often with help."', tags: ['Fear', 'Faith'] },
  { sub: 'The Gift of Desperation', sum: 'Desperation brought many of us to recovery. What felt like our lowest point was actually the beginning of the most important change of our lives.', q: '"Desperation is not the end — it is often the door. We just have to be willing to walk through it."', tags: ['Desperation', 'Hope'] },
  { sub: 'Practicing Kindness', sum: 'Simple acts of kindness connect us to others and remind us that recovery is about far more than just not drinking.', q: '"Kindness costs nothing and changes everything. In recovery, we try to give it freely."', tags: ['Kindness', 'Love'] },
  { sub: 'Spiritual Growth', sum: 'Spiritual growth is not about religion — it is about becoming more honest, open, and willing. It happens gradually and often when we are not looking.', q: '"Spiritual progress is not measured in peak experiences but in the daily choices we make when no one is watching."', tags: ['Spirituality', 'Progress'] },
  { sub: 'Dealing with Criticism', sum: 'Criticism can trigger our defenses. In recovery, we learn to pause, listen, consider the grain of truth, and respond rather than react.', q: '"The person who never hears criticism never grows. Learning to sit with it rather than fight it is a real skill."', tags: ['Criticism', 'Restraint'] },
  { sub: 'Joy in Sobriety', sum: 'Recovery is not just about avoiding pain — it is about discovering genuine joy, laughter, and connection that we thought we had lost forever.', q: '"Joy in sobriety is not the absence of problems. It is the presence of something worth protecting."', tags: ['Joy', 'Happiness'] },
  { sub: 'When Life Gets Hard', sum: 'Difficult times test our recovery but also reveal its depth. The tools of the program work in every situation — if we actually use them.', q: '"Hard times are not proof that recovery is not working. They are proof that we need it."', tags: ['Adversity', 'Resilience'] },
  { sub: 'Surrendering Outcomes', sum: 'We do the footwork and leave the results to a Higher Power. Surrendering outcomes frees us from anxiety and the exhaustion of control.', q: '"We are responsible for the effort. We are not responsible for the result. That is a Higher Power\'s job."', tags: ['Surrender', 'Outcomes'] },
  { sub: 'The Power of Meetings', sum: 'Meetings are where we share, listen, and connect. They remind us we are not alone and keep our recovery alive one share at a time.', q: '"Meetings are where recovery lives. They are not perfect, but they are where we find each other."', tags: ['Meetings', 'Fellowship'] },
  { sub: 'Living Amends', sum: 'Some amends cannot be made in words. Living amends means consistently showing up as a changed person, day after day.', q: '"A living amends cannot be undone. It is the changed life, lived one day at a time."', tags: ['Amends', 'Change'] },
  { sub: 'Recovery Wisdom', sum: 'Recovery distills deep truths into simple practices: do the next right thing, stay in the present, help others, keep it simple.', q: '"The wisdom of recovery is simple — but simple is not the same as easy."', tags: ['Wisdom', 'Simplicity'] },
];

// Step Talk — The 12 Steps of twelve-step recovery
const STEP_CARDS = [
  { sub: 'Step 1 — Powerlessness', sum: 'We admitted we were powerless over alcohol — that our lives had become unmanageable. This honest admission is the foundation upon which all other steps rest.', q: '"Admitting powerlessness is not defeat — it is the first act of genuine courage in recovery."', tags: ['Step 1', 'Powerlessness'] },
  { sub: 'Step 1 — Unmanageability', sum: 'Unmanageability shows up in every area of life — relationships, finances, emotions, and health. Step 1 asks us to see the full picture honestly.', q: '"The admission that we were out of control turned out to be the bedrock on which a new life could be built."', tags: ['Step 1', 'Unmanageability'] },
  { sub: 'Step 2 — Came to Believe', sum: 'Came to believe that a Power greater than ourselves could restore us to sanity. This step requires nothing more than an open mind and willingness.', q: '"The only thing we need to begin this step is the willingness to believe that our own best thinking is not enough."', tags: ['Step 2', 'Faith'] },
  { sub: 'Step 2 — Restored to Sanity', sum: 'Step 2 invites us to recognize the insanity of our pattern and believe that something greater can restore us to a sane way of living.', q: '"We had tried everything we knew. Step 2 asks us to try something we did not know — something greater than ourselves."', tags: ['Step 2', 'Sanity'] },
  { sub: 'Step 3 — Turning It Over', sum: 'Made a decision to turn our will and our lives over to the care of a Higher Power as we understood it. Step 3 is a decision — not a feeling.', q: '"Step 3 is not about feeling ready. It is about making a decision before we are ready, and the feeling follows."', tags: ['Step 3', 'Surrender'] },
  { sub: 'Step 3 — Self-Will vs. Higher Will', sum: 'Step 3 addresses our central problem: self-will run riot. When we try to control everything, life becomes unmanageable. Turning it over brings peace.', q: '"Self-centeredness was not a character flaw — it was a survival strategy. Step 3 offers us a better one."', tags: ['Step 3', 'Self-Will'] },
  { sub: 'Step 4 — The Resentment Inventory', sum: 'Step 4 begins with listing resentments — who we resent, why, and what our part was. This written inventory reveals patterns driving our behavior.', q: '"Resentment is a primary threat to lasting sobriety. Step 4 is how we drain the wound."', tags: ['Step 4', 'Resentment'] },
  { sub: 'Step 4 — The Fear Inventory', sum: 'The fear inventory in Step 4 identifies the fears that drive our actions. Listing and sharing them begins the process of releasing their grip on us.', q: '"Most of our destructive behavior was rooted in fear. Step 4 names it so we can finally face it."', tags: ['Step 4', 'Fear'] },
  { sub: 'Step 4 — Searching and Fearless', sum: 'A searching and fearless moral inventory means holding nothing back. Step 4 requires honest examination of resentments, fears, and harms caused.', q: '"A searching inventory is one we write as if no one will read it — and then share as if everyone should."', tags: ['Step 4', 'Inventory'] },
  { sub: 'Step 5 — Admitting the Exact Nature', sum: 'Admitted to a Higher Power, to ourselves, and to another human being the exact nature of our wrongs. Step 5 breaks through the isolation of shame.', q: '"Secrets keep us sick. Step 5 is the step where we stop being alone with who we really are."', tags: ['Step 5', 'Honesty'] },
  { sub: 'Step 5 — Sharing with Another', sum: 'Sharing our inventory with another person is one of the most transformative acts in recovery. Being truly known — and accepted anyway — is healing.', q: '"We spent years hiding who we really were. Step 5 is the first time many of us were fully seen and not rejected."', tags: ['Step 5', 'Sharing'] },
  { sub: 'Step 6 — Entirely Ready', sum: 'Were entirely ready to have a Higher Power remove all these defects of character. Step 6 is about willingness — even when we cling to familiar defects.', q: '"Step 6 does not require perfection — only honest willingness. We do not have to want to let go. We just have to be willing to want to."', tags: ['Step 6', 'Willingness'] },
  { sub: 'Step 6 — Letting Go of Defects', sum: 'Some character defects feel like old friends. Step 6 asks us to become willing to let them all go — even the ones that once protected or served us.', q: '"The defects that kept us safe in addiction are the same ones that block us in recovery."', tags: ['Step 6', 'Character Defects'] },
  { sub: 'Step 7 — Humbly Asked', sum: 'Humbly asked a Higher Power to remove our shortcomings. Step 7 is grounded in humility — seeing ourselves as we truly are and asking for help to change.', q: '"Humility is not thinking less of ourselves. It is being willing to be changed by something greater."', tags: ['Step 7', 'Humility'] },
  { sub: 'Step 7 — The Practice of Surrender', sum: 'Asking for our shortcomings to be removed so we can better serve others. A daily practice of surrender and trust in a power greater than ourselves.', q: '"We do not ask for perfection — only for the willingness to stop standing in our own way."', tags: ['Step 7', 'Prayer'] },
  { sub: 'Step 8 — Making the List', sum: 'Made a list of all persons we had harmed and became willing to make amends to them all. Step 8 is about willingness and honest preparation.', q: '"The list in Step 8 is not about guilt — it is about responsibility. We write it to become willing to repair what we broke."', tags: ['Step 8', 'Willingness'] },
  { sub: 'Step 8 — Willingness to Make Amends', sum: 'Step 8 asks us to become willing to face those we have harmed. Some names come easily; others require prayer and time. Willingness is the only requirement.', q: '"We cannot always make every amends immediately. Step 8 asks us to start by becoming willing."', tags: ['Step 8', 'Amends'] },
  { sub: 'Step 9 — Making Direct Amends', sum: 'Made direct amends to such people wherever possible, except when to do so would injure them or others. Step 9 requires courage, sensitivity, and guidance.', q: '"An amends is not about how we feel doing it. It is about cleaning up what we left behind."', tags: ['Step 9', 'Amends'] },
  { sub: 'Step 9 — The Promises', sum: 'Through working Step 9, something remarkable begins: new freedom, new happiness, peace, and the ability to help others who are still suffering.', q: '"The promises of recovery are not handed to us — they are revealed through the work of making things right."', tags: ['Step 9', 'Promises'] },
  { sub: 'Step 9 — Living Amends', sum: 'Some amends cannot be made in words alone. Living amends means consistently showing up as a changed person — day after day, choice after choice.', q: '"The best amends we can make is to become someone our past could not have imagined."', tags: ['Step 9', 'Living Amends'] },
  { sub: 'Step 10 — Continued Personal Inventory', sum: 'Continued to take personal inventory and when we were wrong promptly admitted it. Step 10 is the maintenance step that keeps recovery current and honest.', q: '"We watch for selfishness, dishonesty, resentment, and fear — not as punishment, but as maintenance."', tags: ['Step 10', 'Inventory'] },
  { sub: 'Step 10 — Spot-Check Inventory', sum: 'A spot-check inventory can be done anytime during the day. When disturbed, we pause and honestly ask what is really driving the feeling.', q: '"When something bothers us, the question is not what they did — it is what we are going to do about our part."', tags: ['Step 10', 'Daily Practice'] },
  { sub: 'Step 11 — Prayer and Meditation', sum: 'Sought through prayer and meditation to improve our conscious contact with a Higher Power, seeking guidance and the strength to follow it.', q: '"Prayer and meditation are not about changing a Higher Power\'s mind. They are about changing our own."', tags: ['Step 11', 'Prayer'] },
  { sub: 'Step 11 — Morning Routine', sum: 'Step 11 suggests starting the day in prayer and reflection — asking for direction, clarity, and freedom from self-will before the day begins.', q: '"Beginning the day in conscious contact sets the tone for everything that follows."', tags: ['Step 11', 'Morning Practice'] },
  { sub: 'Step 11 — Conscious Contact', sum: 'Step 11 deepens our relationship with a Higher Power through daily practice. It is less about getting answers and more about staying connected.', q: '"Conscious contact is not a feeling we achieve — it is a practice we maintain."', tags: ['Step 11', 'Conscious Contact'] },
  { sub: 'Step 12 — Carrying the Message', sum: 'Having had a spiritual awakening as the result of these steps, we carry this message to others and practice these principles in all our affairs.', q: '"Nothing protects our own sobriety like helping someone else find theirs."', tags: ['Step 12', 'Service'] },
  { sub: 'Step 12 — Spiritual Awakening', sum: 'Step 12 begins with the recognition that something has changed — a personality shift that makes recovery not just possible but livable.', q: '"The awakening is usually not a moment. It is the gradual realization that we have become someone different."', tags: ['Step 12', 'Awakening'] },
  { sub: 'Step 12 — Practice These Principles', sum: 'Step 12 challenges us to practice recovery principles not just in meetings, but in every area of life — at work, at home, and in every relationship.', q: '"The steps are not a meeting thing — they are a life thing. Step 12 asks us to live them everywhere."', tags: ['Step 12', 'Principles'] },
];

const BILL_CARDS = [
  { sub: 'Humility — Foundation of Growth', sum: 'Self-reliance can become our greatest obstacle. Humility opens the door to all other virtues and genuine spiritual growth.', q: '"Pain honestly faced is never wasted — it becomes the foundation of genuine wisdom and compassion."', tags: ['Humility', 'Growth'] },
  { sub: 'Willingness to Grow', sum: 'Willingness to grow is the essence of spiritual development. Difficulty is not punishment — it is often the very instrument of progress.', q: '"Growth requires that we become willing to be changed before we are ready — and trust that the change will be worth it."', tags: ['Willingness', 'Progress'] },
  { sub: 'The Language of the Heart', sum: 'Genuine recovery writing and wisdom is ultimately about love, connection, and the kind of honest communication that heals.', q: '"The most powerful thing one person in recovery can say to another is simply: I know. I have been there. And it gets better."', tags: ['Communication', 'Heart'] },
  { sub: 'Depression and Recovery', sum: 'Depression is not a sign that recovery has failed. Honesty about it — rather than hiding it — is itself an act of courage that helps others.', q: '"Being honest about our struggles does not undermine recovery. It is what recovery looks like in real life."', tags: ['Depression', 'Honesty'] },
  { sub: 'Gratitude as Foundation', sum: 'Gratitude is not a feeling we wait for — it is a practice we choose. It is the essential attitude for maintaining sobriety and growing spiritually.', q: '"No act of service, however small, leaves us unchanged. Gratitude and giving are inseparable in recovery."', tags: ['Gratitude', 'Service'] },
  { sub: 'Unity in Diversity', sum: 'The strength of any recovery community lies in its diversity. Every background, belief, and experience enriches the whole.', q: '"Recovery does not ask where you came from. It only asks whether you are willing to change."', tags: ['Unity', 'Diversity'] },
  { sub: 'The Role of Suffering', sum: 'Suffering has purpose — it strips away pretense and opens us to genuine change. It is not wasted when we bring it honestly into recovery.', q: '"The suffering we survived is exactly what qualifies us to help someone else through theirs."', tags: ['Suffering', 'Purpose'] },
  { sub: 'Spiritual Awakening', sum: 'Early recovery founders recognized that most spiritual awakenings are gradual — a slow, accumulating shift rather than a sudden flash of light.', q: '"Most awakenings do not arrive like lightning. They come like a tide — and we only notice how far it has moved when we look back at the shore."', tags: ['Awakening', 'Spirituality'] },
  { sub: 'Leadership in Service', sum: 'Genuine recovery leadership is not governance — it is service. Those who lead best do so by example, not by authority.', q: '"The best leaders in recovery are the ones who make everyone around them feel less alone."', tags: ['Leadership', 'Service'] },
  { sub: 'Emotional Sobriety', sum: 'Emotional sobriety is the next frontier beyond physical sobriety — learning to live with life on its own terms, without needing to change how we feel.', q: '"Emotional sobriety is the ongoing work of becoming free — not from difficulty, but from the tyranny of our reaction to it."', tags: ['Emotional Sobriety', 'Growth'] },
  { sub: 'Courage Under Fire', sum: 'Recovery asks us to keep going despite imperfection — to face criticism, doubt, and our own character defects without giving up.', q: '"We are not asked to be perfect. We are asked to be willing — and to keep showing up despite our imperfections."', tags: ['Courage', 'Imperfection'] },
  { sub: 'The Gift of Anonymity', sum: 'Anonymity protects both the individual and the community from the dangers of ego and public recognition at the expense of principle.', q: '"When we lead with our recovery rather than our name, we remind everyone that the message matters more than the messenger."', tags: ['Anonymity', 'Ego'] },
  { sub: 'Love and Tolerance', sum: 'Love and tolerance of others is the code by which we try to live. Recovery transforms us into people capable of genuine and patient love.', q: '"Recovery asks us to love people we would never have chosen — and in doing so, we become someone we never expected."', tags: ['Love', 'Tolerance'] },
  { sub: 'Self-Examination', sum: 'Relentless but compassionate self-examination is the path to freedom. Honest self-appraisal is not about shame — it is about clarity.', q: '"Self-examination is not a punishment. It is how we stay honest with ourselves and useful to others."', tags: ['Self-Examination', 'Honesty'] },
  { sub: 'Fear and Faith', sum: 'Fear is the root of most problems in recovery. Faith — in something greater than our own thinking — is its most reliable antidote.', q: '"Where fear contracts, faith expands. The practice of recovery is learning to choose faith — especially when fear is louder."', tags: ['Fear', 'Faith'] },
  { sub: 'Service Above Self', sum: 'A life of service is the surest path to lasting recovery. Giving to others without expectation of return is the most protective act we know.', q: '"Service is not a chore in recovery — it is the thing that most reliably keeps us well."', tags: ['Service', 'Giving'] },
  { sub: 'Patience with Progress', sum: 'We claim spiritual progress rather than spiritual perfection. Growth is a lifelong journey, not a destination we arrive at.', q: '"Progress, not perfection — this is not just a slogan. It is the most honest description of what recovery actually looks like."', tags: ['Patience', 'Progress'] },
  { sub: 'Dealing with Resentment', sum: 'Resentment is among the greatest threats to lasting sobriety. Learning to pray for those we resent — however reluctantly — has freed countless people.', q: '"Praying for someone we resent does not mean we forgive them immediately. It means we stop letting them control our peace."', tags: ['Resentment', 'Prayer'] },
  { sub: 'The Fellowship\'s Future', sum: 'A strong recovery community is built on shared principles, not on personalities. Traditions ensure the fellowship survives long after any individual.', q: '"Any fellowship built on principles rather than personalities can outlast its founders. That was always the plan."', tags: ['Future', 'Traditions'] },
  { sub: 'Living with Imperfection', sum: 'Honesty about our own flaws is not a liability — it is one of the most powerful things we can offer someone who is still suffering.', q: '"The program does not work for perfect people. It works for imperfect people who are willing to keep trying."', tags: ['Imperfection', 'Willingness'] },
  { sub: 'A Partnership That Changed Everything', sum: 'The earliest twelve-step recovery began between two people who discovered that one struggling person talking honestly with another could keep both of them sober.', q: '"Two people who could not stay sober alone figured out that together, they could. That is the entire foundation."', tags: ['Partnership', 'Fellowship'] },
  { sub: 'Spiritual Roots of the Steps', sum: 'The twelve steps drew on spiritual principles already understood by many traditions: honesty, unselfishness, and love. They gave those principles a practical framework.', q: '"The steps did not invent these principles. They gave us a structure to actually live them — one day at a time."', tags: ['Spirituality', 'History'] },
  { sub: 'Emotional Sobriety — The Next Frontier', sum: 'Emotional sobriety means freedom from the tyranny of our own feelings and the demands we place on life and other people.', q: '"When we stop needing everything to be different than it is, we find that most of what we needed was already there."', tags: ['Emotional Sobriety', 'Maturity'] },
  { sub: 'The Traditions — A Living Legacy', sum: 'The twelve traditions protect the recovery community from the forces that would otherwise tear it apart — ego, money, prestige, and controversy.', q: '"Without shared principles to hold us together, any community will fracture. The traditions are the structure that keeps recovery intact."', tags: ['Traditions', 'Unity'] },
  { sub: 'Anonymity and Humility', sum: 'Declining public recognition to protect the principle of anonymity is an act of humility that benefits the whole community.', q: '"Anonymity reminds us that no individual is more important than the principles — and no recovery more important than the next person\'s."', tags: ['Anonymity', 'Humility'] },
  { sub: 'The Three Legacies of Recovery', sum: 'Recovery, unity, and service — these three legacies together form the complete foundation of twelve-step life. Each depends on the others.', q: '"Service keeps the doors open so that recovery stays possible for the next person who needs it."', tags: ['Service', 'Legacy'] },
  { sub: 'Wrestling with Doubt', sum: 'Even those with long-term sobriety wrestle with doubt, depression, and uncertainty. Sharing those struggles honestly is itself an act of recovery.', q: '"Doubt does not mean recovery has failed. It means we are still honest enough to admit we do not have all the answers."', tags: ['Doubt', 'Vulnerability'] },
  { sub: 'Spirituality vs. Religion', sum: 'Twelve-step recovery is a spiritual program, not a religious one. People of every faith — and none — have found a home in it.', q: '"The only requirement is willingness. Recovery has no monopoly on spirituality — it only has an approach that has worked for millions."', tags: ['Spirituality', 'Inclusivity'] },
  { sub: 'A Vision for Unity', sum: 'The vision for any lasting recovery community is one so deeply rooted in spiritual principles that no personality, crisis, or controversy can destroy it.', q: '"Unity is not uniformity. A recovery community is strongest when its members are free to be different — and still committed to the same principles."', tags: ['Unity', 'Vision'] },
  { sub: 'Surrender as Gateway', sum: 'Surrender is not defeat — it is the gateway to a new life. The paradox at the heart of recovery is that we find freedom by letting go.', q: '"Surrender is the only battle we win by stopping. Everything else in recovery flows from that one act."', tags: ['Surrender', 'Paradox'] },
];

// Recovery Vocabulary — original definitions and key recovery terms
const VOCAB_CARDS = [
  { sub: 'Allergy of the Body', sum: 'Addiction involves a physical component — once the first drink is taken, a craving is triggered that makes stopping nearly impossible through willpower alone.', q: '"Understanding why willpower fails is the first step toward finding what actually works."', tags: ['Medical', 'Allergy'], dq: ['How does understanding addiction as a physical condition change how you view yourself?', 'Why is it important that the craving starts only after the first drink?', 'How would you explain this concept to someone new to recovery?'] },
  { sub: 'Obsession of the Mind', sum: 'The mental obsession convinces a person they can drink safely despite all evidence to the contrary. It precedes the first drink and overrides rational thinking.', q: '"The problem is not the drink itself — it is the thought that one drink will be fine this time."', tags: ['Mental', 'Obsession'], dq: ['Can you recall a time the mental obsession convinced you it was safe to drink?', 'What tools help you interrupt that thought before it becomes action?', 'How does talking to someone else help break the mental obsession?'] },
  { sub: 'Phenomenon of Craving', sum: 'Once the first drink is taken, a physical craving kicks in — an overwhelming need for more. This distinguishes addiction from ordinary habit or social drinking.', q: '"One drink sets off something in us that ordinary people simply do not experience."', tags: ['Craving', 'Physical'], dq: ['How does the craving after the first drink differ from simply wanting a drink?', 'Why does willpower alone fail to stop it once it begins?', 'How does this concept help explain why moderation does not work for addicts?'] },
  { sub: 'Spiritual Malady', sum: 'Beneath the addiction lies a deeper condition — restlessness, irritability, and discontent that no substance ever truly relieved for long.', q: '"We were not drinking because life was bad. We were drinking because we felt empty, and we had found nothing yet to fill that emptiness."', tags: ['Spiritual', 'Malady'], dq: ['How do you experience restlessness, irritability, or discontent in your own life?', 'Why is treating the inner condition essential — not just stopping drinking?', 'Which steps have helped most with that underlying emptiness?'] },
  { sub: 'Psychic Change', sum: 'A profound inner change — a shift in perspective and values — is what makes lasting recovery possible. It cannot be produced by willpower alone.', q: '"We did not change by deciding to. We changed by surrendering to a process larger than our own willpower."', tags: ['Psychic Change', 'Transformation'], dq: ['What does a profound personality change look like in your recovery?', 'Was your change sudden or gradual, and how did you recognize it?', 'Why is inner transformation — not just sobriety — necessary for lasting change?'] },
  { sub: 'Cunning, Baffling, Powerful', sum: 'Addiction is cunning in how it deceives, baffling in how we repeat the same mistakes, and powerful in the grip it maintains long after we think we are safe.', q: '"The most dangerous moment is when we start to believe we have it completely figured out."', tags: ['Addiction', 'Warning'], dq: ['In what ways has addiction been cunning in your experience?', 'What makes it baffling — why do we repeat the same mistakes?', 'How do you stay vigilant even after years of sobriety?'] },
  { sub: 'Half Measures', sum: 'A halfhearted or partial effort at recovery leaves us vulnerable. Full commitment to the process is what produces lasting and genuine change.', q: '"We cannot give half of ourselves to recovery and expect to get a whole life back."', tags: ['Commitment', 'Action'], dq: ['Where in your recovery have you tried half measures, and what happened?', 'What does full commitment to the process look like in daily practice?', 'Why do half measures consistently fall short?'] },
  { sub: 'Moral Inventory', sum: 'A searching and fearless moral inventory — written, honest, and thorough — reveals the patterns that drove our addiction and caused harm to others.', q: '"Writing it down makes it permanent. We cannot revise it when it becomes uncomfortable."', tags: ['Inventory', 'Step 4'], dq: ['What patterns did your moral inventory reveal about your behavior?', 'Why must the inventory be both searching and fearless?', 'How did writing it down differ from just thinking about your past?'] },
  { sub: 'Character Defects', sum: 'Character defects are deeply ingrained patterns — selfishness, dishonesty, fear, resentment — that cause harm and block growth. Steps 6 and 7 address them directly.', q: '"The traits that once protected us in addiction become the very things that keep us stuck in recovery."', tags: ['Defects', 'Character'], dq: ['Which character defect has been the hardest for you to release?', 'How do selfishness, dishonesty, fear, and resentment show up in your life today?', 'What does being entirely ready for change actually feel like?'] },
  { sub: 'Shortcomings', sum: 'Shortcomings are the ways we fall short of the people we could be. Step 7 invites us to humbly ask a Higher Power to remove them — not by force of will, but by grace.', q: '"We are not asked to fix ourselves — only to be willing to be changed."', tags: ['Shortcomings', 'Humility'], dq: ['How do you distinguish between a shortcoming and a character defect?', 'Why does this step emphasize humility in asking for change?', 'In what ways do you still fall short of the person you want to be?'] },
  { sub: 'Amends', sum: 'Amends go beyond apology — they involve honestly acknowledging harm done, taking responsibility, and making restitution wherever possible through Steps 8 and 9.', q: '"An amends is a commitment to change, not just a request for forgiveness."', tags: ['Amends', 'Restitution'], dq: ['What is the difference between making amends and simply saying sorry?', 'How do you decide when making amends might cause more harm than good?', 'What has the amends process taught you about taking real responsibility?'] },
  { sub: 'Living Amends', sum: 'When direct contact would cause more harm, or when words alone are not enough, a living amends is the daily demonstration of genuine change through consistent behavior.', q: '"The living amends is the one that cannot be taken back — it is the changed life, lived day after day."', tags: ['Living Amends', 'Behavior'], dq: ['When is a living amends more appropriate than a direct one?', 'How do you demonstrate change through action rather than words?', 'What living amends are you actively making right now?'] },
  { sub: 'Rigorous Honesty', sum: 'Rigorous honesty goes beyond not lying — it means being truthful about our motives, fears, and actions, especially with ourselves. It is the foundation of recovery.', q: '"Recovery begins the moment we stop deceiving ourselves — that is the only honesty that actually matters."', tags: ['Honesty', 'Foundation'], dq: ['How does rigorous honesty differ from simply not telling lies?', 'Where do you struggle most with being honest with yourself?', 'Why is honesty described as the foundation of recovery?'] },
  { sub: 'Self-Will Run Riot', sum: 'Self-will run riot — the compulsive need to control people, places, and things — is at the root of most problems in addiction and early recovery.', q: '"Self-centeredness is not a personality quirk. For us, it was a survival strategy that stopped working."', tags: ['Self-Will', 'Control'], dq: ['Where does your self-will still try to control outcomes?', 'How is self-will the opposite of surrender?', 'What happens in your life when self-centeredness takes over?'] },
  { sub: 'Turning It Over', sum: 'Turning it over means releasing our grip on a problem, decision, or outcome and trusting a Higher Power with it. It is the practical heart of Step 3.', q: '"We cannot hold on with both hands and ask for help at the same time. We have to let go first."', tags: ['Surrender', 'Step 3'], dq: ['What does turning it over look like in your daily practice?', 'What is hardest for you to release to a Higher Power?', 'How has turning something over changed the outcome for you?'] },
  { sub: 'The Promises of Recovery', sum: 'Working the steps brings real rewards — new freedom, happiness, peace, and the ability to help others — that people in early recovery can barely imagine are possible.', q: '"The gifts of sobriety are not handed to us before the work — they are revealed through it."', tags: ['Promises', 'Hope'], dq: ['Which recovery promises have come true most clearly in your life?', 'How did doing the work lead to new freedom or happiness?', 'Which promise are you still waiting to fully experience?'] },
  { sub: 'Spiritual Awakening', sum: 'A spiritual awakening is a shift in perspective and personality — often gradual — that makes lasting recovery possible. It is usually recognized in hindsight.', q: '"Most of us did not notice our spiritual awakening happening. We only recognized it by looking back at who we used to be."', tags: ['Awakening', 'Step 12'], dq: ['Was your spiritual awakening sudden or gradual?', 'What new way of thinking or living has it brought?', 'How do you recognize a spiritual awakening in someone else?'] },
  { sub: 'Higher Power', sum: 'A Higher Power is whatever force greater than ourselves we choose to rely on. Recovery requires no specific belief — only willingness to accept help beyond our own thinking.', q: '"The only requirement for a Higher Power is that it be greater than the problem we cannot solve alone."', tags: ['Higher Power', 'Open-Minded'], dq: ['How has your understanding of a Higher Power evolved in recovery?', 'Why is willingness more important than a specific belief?', 'How do you rely on your Higher Power in everyday situations?'] },
  { sub: 'As We Understood', sum: 'This phrase ensures inclusivity — each person defines their own understanding of a Higher Power. Recovery has no religious requirement, only a spiritual suggestion.', q: '"The God of your understanding is personal. No one else gets to define it for you."', tags: ['Higher Power', 'Inclusivity'], dq: ['Why is this phrase so important to the accessibility of recovery?', 'How has your own understanding of a Higher Power evolved over time?', 'How does this language make the program available to people of all beliefs?'] },
  { sub: 'The Turning Point', sum: 'The turning point is the moment we stop fighting and start surrendering — when we finally become willing to accept help we could not accept before.', q: '"The turning point is not where we gave up. It is where we finally gave in to something that could actually help."', tags: ['Decision', 'Surrender'], dq: ['Can you describe your own turning point moment?', 'What does the shift from fighting to surrendering feel like?', 'Why is this described as a decision rather than a feeling?'] },
  { sub: 'Hitting Bottom', sum: 'For many, recovery began only after reaching a point of complete breakdown — physical, emotional, and spiritual — that finally made denial impossible to maintain.', q: '"The bottom is the place where the only direction left is up, and we finally become willing to move."', tags: ['Bottom', 'Despair'], dq: ['What did hitting bottom mean for you personally?', 'Why does the severity of the bottom vary so much from person to person?', 'How did your lowest point eventually become the beginning of your recovery?'] },
  { sub: 'The Mental Blank Spot', sum: 'The mental blank spot is the moment when an addicted person forgets all consequences and reaches for the first drink anyway — the obsession overriding reason.', q: '"In that moment, every good reason to stay sober simply vanished — and that is what made it so terrifying."', tags: ['Mental', 'Defense'], dq: ['Have you experienced the mental blank spot — the moment all consequences disappeared?', 'Why does knowledge of consequences alone fail to stop addiction?', 'What spiritual or practical defense do you use against it today?'] },
  { sub: 'Conscious Contact', sum: 'Conscious contact is an active, aware relationship with a Higher Power — maintained through daily prayer, meditation, and intentional openness.', q: '"Conscious contact is not a feeling we wait for. It is a practice we show up to, whether we feel it or not."', tags: ['Prayer', 'Meditation'], dq: ['What does conscious contact with a Higher Power feel like for you?', 'How do prayer and meditation differ in deepening that relationship?', 'What daily practice helps you maintain it?'] },
  { sub: 'Carrying the Message', sum: 'Carrying the message means sharing our experience, strength, and hope — not advice or opinions — with people who are still suffering from addiction.', q: '"We carry the message best not by telling people what to do, but by showing them who we have become."', tags: ['Service', 'Step 12'], dq: ['How do you carry the message in your daily life?', 'Why is sharing experience and hope more effective than giving advice?', 'What is the difference between carrying the message and carrying the person?'] },
  { sub: 'Restless, Irritable, Discontented', sum: 'Being sober but spiritually untreated means still carrying the restlessness, irritability, and discontent that drove the addiction — just without the temporary relief.', q: '"Sobriety without inner work just means being uncomfortable without relief. That is why doing the work matters."', tags: ['Dry Recovery', 'Spiritual'], dq: ['Have you experienced being physically sober but emotionally miserable?', 'What is the difference between sobriety and actual recovery?', 'What do you do when these feelings start creeping back in?'] },
  { sub: 'Repeating the Same Mistake', sum: 'The pattern of returning to drinking despite knowing the consequences illustrates that addiction is not a failure of willpower — it is a deeper condition requiring a deeper solution.', q: '"Knowing exactly what will happen and doing it anyway — that is what tells us we are dealing with more than ordinary habit."', tags: ['Insanity', 'Pattern'], dq: ['How does this pattern describe your own experience with addiction?', 'Why does knowledge of consequences not stop the behavior?', 'What finally broke through when willpower kept failing?'] },
  { sub: 'Two Types of Awakening', sum: 'Spiritual awakenings can be sudden and dramatic or quiet and gradual. Both are equally real. Most people in recovery experience the slow, accumulating kind.', q: '"Not all awakenings arrive like lightning. Most come like a slow sunrise — barely noticed until the world is already bright."', tags: ['Awakening', 'Types'], dq: ['Do you relate more to a sudden spiritual experience or the gradual kind?', 'Why is it important to know that both are equally valid?', 'How has your own spiritual awakening developed over time?'] },
  { sub: 'Daily Reprieve', sum: 'Recovery is not a permanent cure but a daily reprieve that depends on actively maintaining our spiritual condition. Each day requires renewed intention and action.', q: '"Recovery is not something we achieve and then own. It is something we maintain — one day at a time, every day."', tags: ['Daily', 'Maintenance'], dq: ['What does the daily reprieve mean for how you approach each morning?', 'How do you maintain your spiritual condition on a daily basis?', 'Why is recovery described as a reprieve rather than a permanent cure?'] },
  { sub: 'Reaching Out to Others', sum: 'Reaching out to someone still suffering is one of the most powerful tools in recovery — for both the person asking for help and the one offering it.', q: '"The phone call we make to help someone else often does more for our own sobriety than anything we do for ourselves."', tags: ['Service', 'Twelfth Step'], dq: ['How does reaching out to help someone else strengthen your own recovery?', 'What has been your experience trying to help someone still struggling?', 'Why does service to others provide such reliable protection from relapse?'] },
  { sub: 'Keep It Simple', sum: 'The program works best when we stop overcomplicating it — work the steps, attend meetings, be honest, help others, and trust the process one day at a time.', q: '"When we overthink recovery, we are usually trying to find a loophole. Keep it simple and do the work."', tags: ['Slogans', 'Simplicity'], dq: ['Where in your recovery do you tend to overcomplicate things?', 'How does keeping it simple help you stay focused on what matters?', 'What does trusting the process look like for you day to day?'] },
];

// 12 & 12 — original paraphrased content covering all 12 steps and 12 traditions
const TWELVE_CARDS = [
  { sub: 'Step 1 — Admitting Powerlessness', sum: 'The foundation of all recovery is the honest admission that we are powerless over alcohol — and that our lives had become unmanageable as a result. Without this admission, no step will work.', q: '"Surrender is not failure. It is the beginning of everything that actually works."', tags: ['Step 1', 'Powerlessness'] },
  { sub: 'Step 2 — Coming to Believe', sum: 'Step 2 invites us to believe that a power greater than ourselves can restore us to sanity. It asks only for open-mindedness — not a specific belief system.', q: '"The willingness to believe something greater can help us is itself a form of spiritual progress."', tags: ['Step 2', 'Belief'] },
  { sub: 'Step 3 — Decision to Turn It Over', sum: 'Step 3 is a decision — not a feeling. We choose to turn our will and our lives over to the care of a Higher Power, as we understand it, and then we act on that decision daily.', q: '"The decision is made once. The practice of it is made every single day."', tags: ['Step 3', 'Surrender'] },
  { sub: 'Step 4 — Searching Moral Inventory', sum: 'A thorough, written examination of our resentments, fears, and harms to others. Step 4 is about clarity, not shame — seeing ourselves honestly so we can begin to change.', q: '"What we write in Step 4 cannot later be quietly revised in our memory. That is why writing it down matters."', tags: ['Step 4', 'Inventory'] },
  { sub: 'Step 5 — Admitted to God and Another', sum: 'We share our inventory with a Higher Power, ourselves, and another human being. Being fully known by someone else and still accepted is a profound healing experience.', q: '"Being heard without judgment by another person is one of the most healing things a human being can experience."', tags: ['Step 5', 'Confession'] },
  { sub: 'Step 6 — Ready for Change', sum: 'Step 6 asks us to become entirely ready to have our character defects removed — not to remove them ourselves, but to stop clinging to the ones we find comfortable.', q: '"Readiness means we have stopped defending the very patterns that have been hurting us."', tags: ['Step 6', 'Readiness'] },
  { sub: 'Step 7 — Humbly Asked', sum: 'Having become ready, we humbly ask our Higher Power to remove our shortcomings. This step is about humility — asking for change rather than willing it into existence.', q: '"We do not ask to become perfect. We ask to become useful, and to stop causing unnecessary harm."', tags: ['Step 7', 'Humility'] },
  { sub: 'Step 8 — List of Those Harmed', sum: 'We make a list of every person we have harmed through our addiction and become willing to make amends to them all — regardless of what they may have done to us.', q: '"The willingness to make amends is the moment we stop being defined by our past behavior."', tags: ['Step 8', 'Amends'] },
  { sub: 'Step 9 — Making Direct Amends', sum: 'Wherever possible, we make direct amends to those we have harmed, except when doing so would cause further injury. This step requires courage, humility, and real action.', q: '"Amends are not performed to feel better about ourselves. They are made because someone was harmed and deserves acknowledgment."', tags: ['Step 9', 'Amends'] },
  { sub: 'Step 10 — Continued Personal Inventory', sum: 'We continue to take personal inventory daily, and when we are wrong, we promptly admit it. This maintenance step keeps our side of the street clean going forward.', q: '"The goal is not to be perfect — it is to be consistently honest and willing to course-correct."', tags: ['Step 10', 'Maintenance'] },
  { sub: 'Step 11 — Prayer and Meditation', sum: 'Step 11 deepens our conscious contact with a Higher Power through prayer and meditation, asking only for knowledge of what we should do and the strength to carry it out.', q: '"We pray to know what to do. We meditate to hear the answer."', tags: ['Step 11', 'Prayer'] },
  { sub: 'Step 12 — Spiritual Awakening and Service', sum: 'Having had a spiritual awakening through working the steps, we carry this message to others who are still suffering and practice these principles in every area of our lives.', q: '"We protect what we have found by freely giving it away."', tags: ['Step 12', 'Service'] },
  { sub: 'Tradition 1 — Our Common Welfare', sum: 'Our common welfare must come first — individual recovery depends on group unity. The first tradition reminds us that none of us is more important than the group as a whole.', q: '"In the fellowship, the group conscience is wiser than any one member — even when it does not feel that way."', tags: ['Tradition 1', 'Unity'] },
  { sub: 'Tradition 2 — One Ultimate Authority', sum: 'For our group purpose, there is one ultimate authority — a loving Higher Power, expressed through our group conscience. Our leaders are servants, not governors.', q: '"True leadership in recovery means facilitating — not controlling — the group conscience."', tags: ['Tradition 2', 'Leadership'] },
  { sub: 'Tradition 3 — Membership Requirements', sum: 'The only requirement for membership is a desire to stop drinking. This tradition ensures the doors of recovery remain open to anyone who sincerely asks for help.', q: '"No one is disqualified from recovery by their past. The only requirement is wanting something different."', tags: ['Tradition 3', 'Inclusion'] },
  { sub: 'Tradition 4 — Each Group is Autonomous', sum: 'Each group is autonomous — free to run itself as it sees fit — except in matters affecting other groups or the fellowship as a whole. This tradition protects diversity within unity.', q: '"Autonomy without accountability is chaos. The traditions hold both in balance."', tags: ['Tradition 4', 'Autonomy'] },
  { sub: 'Tradition 5 — Primary Purpose', sum: 'Each group has one primary purpose — to carry the message to the addict who still suffers. Everything else is secondary. This keeps the fellowship focused on what matters most.', q: '"When a group loses sight of its primary purpose, everything else starts to drift."', tags: ['Tradition 5', 'Purpose'] },
  { sub: 'Tradition 6 — Outside Issues', sum: 'Fellowship groups should never endorse, finance, or lend their name to outside enterprises. Separation from outside causes protects the fellowship from controversy and distraction.', q: '"The program survives because it stays focused on one thing. The moment it tries to be everything, it risks becoming nothing."', tags: ['Tradition 6', 'Focus'] },
  { sub: 'Tradition 7 — Self-Supporting', sum: 'Every group ought to be fully self-supporting, declining outside contributions. This tradition keeps the fellowship free from financial entanglement and obligated to no one but its members.', q: '"Self-sufficiency is itself a form of integrity. We do not sell our principles."', tags: ['Tradition 7', 'Integrity'] },
  { sub: 'Tradition 8 — Fellowship Service', sum: 'Fellowship service should remain forever non-professional. Twelfth-step work is a labor of love — not commerce. Professionals help us, but they do not replace peer support.', q: '"What we give to each other cannot be purchased. It only works because it is freely given."', tags: ['Tradition 8', 'Service'] },
  { sub: 'Tradition 9 — Minimum Organization', sum: 'Twelve-step groups should never be organized, except as necessary. Committees may be created to serve, but they should never govern. Service structure exists to facilitate, not control.', q: '"The least organization needed to get the work done is the right amount."', tags: ['Tradition 9', 'Organization'] },
  { sub: 'Tradition 10 — No Outside Opinions', sum: 'Twelve-step groups have no opinion on outside issues and must never be drawn into public controversy. This keeps the fellowship available to everyone, regardless of outside views.', q: '"Our silence on outside matters is what keeps us trusted by everyone."', tags: ['Tradition 10', 'Neutrality'] },
  { sub: 'Tradition 11 — Anonymity in Public', sum: 'Our public relations policy is based on attraction rather than promotion. We need always maintain personal anonymity at the level of press, radio, and film.', q: '"Attraction rather than promotion means we let our changed lives speak louder than our words."', tags: ['Tradition 11', 'Anonymity'] },
  { sub: 'Tradition 12 — Spiritual Foundation', sum: 'Anonymity is the spiritual foundation of all our traditions — a constant reminder that principles must always come before personalities in the fellowship.', q: '"Anonymity keeps no single person above the principles that hold everything together."', tags: ['Tradition 12', 'Foundation'] },
];

// Recovery Slogans — public domain wisdom passed down through the fellowship
const SLOGANS_CARDS = [
  // Core / Traditional
  { sub: 'One Day at a Time', sum: 'The cornerstone of recovery thinking. When permanent sobriety feels overwhelming, this slogan makes it manageable — shrink it down to just today, just this hour, just right now.', q: '"You do not have to stay sober forever today. You only have to stay sober today."', tags: ['Core', 'Presence'] },
  { sub: 'Easy Does It', sum: 'Urgency and panic rarely improve a situation. Recovery often calls for slowing down, trusting the process, and resisting the urge to force outcomes we cannot control.', q: '"The answer rarely comes from pushing harder. Sometimes it comes from letting go."', tags: ['Core', 'Patience'] },
  { sub: 'Keep It Simple', sum: 'When we overcomplicate recovery, we are usually looking for a loophole. Simplicity is the antidote — do the next right thing and trust the process, one step at a time.', q: '"The simpler we keep it, the harder it is to talk ourselves out of it."', tags: ['Core', 'Clarity'] },
  { sub: 'First Things First', sum: 'When everything seems urgent, this slogan tells us what must be protected above all else. Sobriety comes first. Everything else depends on it remaining intact.', q: '"Without sobriety, nothing else we value stays."', tags: ['Core', 'Priorities'] },
  { sub: 'Live and Let Live', sum: 'We cannot control others, and trying to drains energy we need for our own recovery. Focus on your own side of the street and allow others to walk their own path.', q: '"The most liberating thing in recovery is realizing we are not in charge of anyone else\'s journey."', tags: ['Core', 'Acceptance'] },
  { sub: 'Let Go and Let God', sum: 'When we have done everything we can, this slogan reminds us to release the outcome to something greater than ourselves. We do the footwork — the results are not our department.', q: '"We do the footwork. The results are not our department."', tags: ['Core', 'Surrender'] },
  { sub: 'This Too Shall Pass', sum: 'No emotion, no crisis, and no uncomfortable moment is permanent. Feelings — even the worst ones — change if we give them time and stay sober through them.', q: '"The storm always passes. The question is whether we are still standing when it does."', tags: ['Core', 'Resilience'] },
  { sub: 'Progress, Not Perfection', sum: 'Recovery does not demand flawlessness — it demands honesty and effort. We aim to grow, not to be faultless, and that is more than enough.', q: '"We are not expected to be perfect. We are expected to keep trying, honestly, one day at a time."', tags: ['Core', 'Growth'] },
  { sub: 'Think, Think, Think', sum: 'Before acting on impulse, pause and consider the consequences. This slogan is the antidote to the reactive, impulsive behavior that caused so much of the damage in our lives.', q: '"The pause between impulse and action is where recovery lives."', tags: ['Core', 'Restraint'] },
  { sub: 'But for the Grace of God', sum: 'This slogan builds humility and compassion. Our recovery is a gift — not an achievement. The person still suffering could easily be us, and we would do well to remember that.', q: '"Wherever we see someone still struggling, we should see ourselves — and remember the grace that helped us out."', tags: ['Core', 'Humility'] },
  { sub: 'There but for the Grace of God Go I', sum: 'Watching someone else struggle is a moment of recognition, not judgment. That could be us. In many ways, it was us. Humility and compassion are the only fitting responses.', q: '"Their story is not so different from ours. The only difference is grace."', tags: ['Core', 'Compassion'] },
  // Recovery Program & Action-Based
  { sub: 'It Works If You Work It', sum: 'The program is not passive. Recovery does not happen by proximity to the rooms or by understanding the steps intellectually — it happens through action, consistently taken.', q: '"Recovery is not a spectator sport. It only works when you actually do it."', tags: ['Action', 'Program'] },
  { sub: 'Keep Coming Back', sum: 'The door to recovery is never permanently closed. No matter how many times we have stumbled, struggled, or slipped away, the invitation to return is always open.', q: '"The door to recovery is never permanently closed. Keep coming back."', tags: ['Action', 'Perseverance'] },
  { sub: 'Fake It Till You Make It', sum: 'Act as if you believe in recovery even when you do not feel it yet. Acting right repeatedly eventually becomes feeling right — behavior leads, emotion follows.', q: '"We cannot think our way into a new way of acting. But we can act our way into a new way of thinking."', tags: ['Action', 'Faith'] },
  { sub: 'Act As If', sum: 'Act as if you already have the faith, courage, or willingness you wish you felt. The action comes first. The feeling catches up when we stop waiting for it to lead.', q: '"Act as if, and in time, you will not have to pretend."', tags: ['Action', 'Courage'] },
  { sub: 'Do the Next Right Thing', sum: 'When overwhelmed by everything ahead, simplify the task — just identify the very next right action and do it. The full path reveals itself one honest step at a time.', q: '"We do not need to see the whole staircase. We just need to take the next step."', tags: ['Action', 'Clarity'] },
  { sub: 'Stick with the Winners', sum: 'Spend time with people whose recovery you admire. The company we keep has an enormous influence on whether we stay sober. Fellowship is not optional — it is protection.', q: '"Show me your friends and I will show you your future."', tags: ['Action', 'Fellowship'] },
  { sub: 'Take It Easy', sum: 'Recovery does not require intensity every moment. Rest, gentleness, and breathing room are part of taking care of ourselves. Pressure and urgency are often symptoms, not solutions.', q: '"Sometimes the most productive thing we can do in recovery is slow down."', tags: ['Action', 'Self-Care'] },
  { sub: 'Keep an Open Mind', sum: 'Closed-mindedness kept us sick. The willingness to hear something new — even something uncomfortable — is one of the most essential tools in lasting recovery.', q: '"Our best thinking got us here. A little open-mindedness might take us somewhere better."', tags: ['Action', 'Willingness'] },
  { sub: 'Suit Up and Show Up', sum: 'Even when we do not feel like it — especially then — showing up is the job. Recovery is built by the discipline of showing up before we feel ready.', q: '"The hardest meeting to get to is always the one we need the most."', tags: ['Action', 'Discipline'] },
  { sub: 'Bring the Body, the Mind Will Follow', sum: 'Get yourself to the meeting, the call, the step work — even when your mind resists. The mind often follows the body into willingness, but it rarely leads.', q: '"The feet know where to go. Let them lead. The thinking can catch up."', tags: ['Action', 'Commitment'] },
  { sub: 'Do Not Quit Before the Miracle Happens', sum: 'Recovery delivers on its promises — but usually on a timeline we did not choose. Quitting just before the breakthrough is the most common tragedy in early recovery.', q: '"The miracle is already in motion. Our job is to stay sober long enough to receive it."', tags: ['Action', 'Hope'] },
  { sub: 'Half Measures Availed Us Nothing', sum: 'A halfhearted recovery leaves us vulnerable. Partial effort at living the program produces partial results — and for many of us, partial results are not enough to survive.', q: '"We cannot give half of ourselves to recovery and expect to get a whole life back."', tags: ['Action', 'Commitment'] },
  { sub: 'Rarely Have We Seen a Person Fail Who Has Thoroughly Followed Our Path', sum: 'The path works. The key word is thoroughly. Those who follow it — honestly, completely, with willingness — rarely fail to find the freedom they were looking for.', q: '"The program has not failed the people who truly work it. The inverse is also true."', tags: ['Action', 'Program'] },
  // Spiritual / Surrender-Based
  { sub: 'Turn It Over', sum: 'Release the grip. Whatever we are holding onto so tightly — an outcome, a resentment, a fear — turn it over to a Higher Power and stop trying to manage it alone.', q: '"We cannot hold on with both hands and ask for help at the same time. Let go first."', tags: ['Spiritual', 'Surrender'] },
  { sub: 'Let Go or Be Dragged', sum: 'Clinging to what we cannot control does not keep us safe — it drags us. Release is not defeat. It is the only path to peace when the situation is beyond our power.', q: '"The river will move with or without our permission. Let go or be dragged."', tags: ['Spiritual', 'Surrender'] },
  { sub: 'God Could and Would If He Were Sought', sum: 'The power to change is available — but it requires seeking. Recovery is not passive. We ask, we seek, we knock, and the door of spiritual change opens from the other side.', q: '"Help is available. The condition is that we have to actually ask for it."', tags: ['Spiritual', 'Prayer'] },
  { sub: 'Thy Will, Not Mine', sum: 'Surrendering our personal agenda to a Higher Power is the heart of Step 3. We stop insisting on our own way and open ourselves to a guidance wiser than our own thinking.', q: '"My best plan got me here. Thy will has somewhere better in mind."', tags: ['Spiritual', 'Surrender'] },
  { sub: 'Seek God\'s Will', sum: 'Rather than asking for what we want, we learn to ask what we are being called to do. Seeking God\'s will shifts us from self-centered thinking to a life of purpose and service.', q: '"The question is not what do I want — it is what am I being called to."', tags: ['Spiritual', 'Purpose'] },
  { sub: 'Trust God', sum: 'Trust is not a feeling — it is a practice. We choose to act as though a Higher Power is trustworthy, even before our experience fully confirms it. The experience comes through action.', q: '"Trust is not built by waiting to feel it. It is built by acting as though it is already true."', tags: ['Spiritual', 'Faith'] },
  { sub: 'Rely Upon God', sum: 'Self-reliance was our first instinct and our greatest failure. Recovery teaches us to rely on something greater — consistently, not just in crisis.', q: '"We relied on ourselves for years and created this mess. Maybe it is time to try something else."', tags: ['Spiritual', 'Surrender'] },
  { sub: 'Let God Lead', sum: 'When we stop insisting on directing every moment, space opens up for guidance we could not receive while our hands were on the wheel. Let go of the wheel long enough to be led.', q: '"The best co-pilot in recovery is also the one we are most reluctant to hand the controls to."', tags: ['Spiritual', 'Guidance'] },
  { sub: 'Pray and Work', sum: 'Prayer without action is wishful thinking. Action without prayer is self-will. Both together — seeking guidance and then doing the footwork — is the spiritual practice of recovery.', q: '"We pray to know what to do. Then we get up and do it."', tags: ['Spiritual', 'Action'] },
  { sub: 'Faith Without Works Is Dead', sum: 'Belief in a Higher Power or in the program is not enough on its own. Recovery requires action — steps worked, meetings attended, service given. Faith that produces nothing changes nothing.', q: '"What we believe matters. What we do about it matters more."', tags: ['Spiritual', 'Action'] },
  // Mindset & Emotional Sobriety
  { sub: 'Acceptance Is the Answer', sum: 'Acceptance is the answer to all our problems today. When we stop fighting reality and start meeting life as it is, peace becomes possible in circumstances we cannot change.', q: '"We cannot change what we refuse to accept. And we cannot accept what we are still pretending is not real."', tags: ['Mindset', 'Acceptance'] },
  { sub: 'Pause When Agitated', sum: 'When we feel the heat rising — anger, fear, irritation — the most powerful thing we can do is pause. Nothing good comes from reacting in agitation. Everything good can come from a moment of stillness.', q: '"The pause is where recovery happens. Everything else is just reaction."', tags: ['Mindset', 'Restraint'] },
  { sub: 'Feelings Aren\'t Facts', sum: 'Our feelings are real experiences — but they are not reliable reporters of reality. What we feel is not always what is true. Learning to distinguish emotion from fact is essential to emotional sobriety.', q: '"I feel it strongly — but that does not mean it is true. Feelings are information, not verdicts."', tags: ['Mindset', 'Emotional Sobriety'] },
  { sub: 'How Important Is It?', sum: 'Before we react, escalate, or obsess — ask this question. Most things we treat as urgent are not. This slogan puts our emotional response in proportion to the actual situation.', q: '"In five years, will this moment matter? If not — how much energy does it deserve right now?"', tags: ['Mindset', 'Perspective'] },
  { sub: 'Live in the Now', sum: 'Anxiety lives in the future. Depression lives in the past. Recovery lives in the present. The only moment where sobriety is actually possible is this one, right now.', q: '"The past is a memory. The future is a plan. The present is the only place where recovery happens."', tags: ['Mindset', 'Presence'] },
  { sub: 'Be Here Now', sum: 'Full presence — in this conversation, this meeting, this moment — is both a recovery practice and a spiritual discipline. The distractions of past and future are where relapse begins.', q: '"The person in front of me deserves the person I am capable of being right now."', tags: ['Mindset', 'Presence'] },
  { sub: 'Easy Does It, But Do It', sum: 'Gentleness with ourselves does not mean complacency. Slow down — yes. But keep moving. Easy Does It is not an excuse to stop. It is permission to go at a sustainable pace.', q: '"Take it easy — but take it. Progress at a pace you can sustain."', tags: ['Mindset', 'Balance'] },
  { sub: 'Keep It in Today', sum: 'We can only stay sober today. Planning for tomorrow\'s sobriety is fine, but worrying about it is a distraction. Today is the only day sobriety is actually possible.', q: '"Tomorrow\'s sobriety is not our job yet. Today\'s is."', tags: ['Mindset', 'Presence'] },
  { sub: 'Stay in the Solution', sum: 'Obsessing over problems keeps us in them. Focusing on the solution — the next action, the next step, the next phone call — moves us through them.', q: '"We cannot solve a problem while remaining fully inside it."', tags: ['Mindset', 'Action'] },
  { sub: 'Don\'t Should on Yourself', sum: '"I should have..." is one of the most toxic phrases in recovery. Shame and self-blame are not motivators — they are anchors. We release the "should" and focus on what we can do now.', q: '"Should keeps us stuck in the past. The only question worth asking is: what can I do now?"', tags: ['Mindset', 'Self-Compassion'] },
  { sub: 'Don\'t Believe Everything You Think', sum: 'Our minds, especially early in recovery, are not reliable narrators. Negative self-talk, distorted beliefs, and catastrophic thinking feel true — but often are not. Check the thought before trusting it.', q: '"Just because I thought it does not make it true. My mind has lied to me before."', tags: ['Mindset', 'Awareness'] },
  { sub: 'Think Less, Feel More', sum: 'Over-thinking is often how we avoid feeling. Recovery asks us to sit with discomfort, process emotion honestly, and stop using analysis as a way to stay out of our own hearts.', q: '"We cannot think our way into feeling better. We have to feel our way through."', tags: ['Mindset', 'Emotional Sobriety'] },
  { sub: 'Let It Begin with Me', sum: 'We cannot change the group, the family, or the world — but we can change how we show up. Recovery starts with us. Unity starts with us. Every principle begins with one willing person.', q: '"We cannot start with anyone else. Change — in the meeting, in the family, in the world — begins with me."', tags: ['Mindset', 'Responsibility'] },
  // Behavior, Boundaries & Relationships
  { sub: 'Principles Before Personalities', sum: 'The traditions and the program are larger than any one person. When a person disappoints us, the principles remain. We do not leave the program because of a person.', q: '"People will always let us down. That is why we trust the principles — not the personalities."', tags: ['Relationships', 'Traditions'] },
  { sub: 'Keep Your Side of the Street Clean', sum: 'We are not responsible for what others do — only for our own behavior, motives, and responses. A clean side of the street is our job. The rest belongs to others and to God.', q: '"I can only clean my side. That job alone is enough."', tags: ['Relationships', 'Responsibility'] },
  { sub: 'Mind Your Own Business', sum: 'Recovery asks us to redirect attention from fixing, managing, or judging others toward doing our own work. What other people do is rarely our problem to solve.', q: '"The energy I spend on other people\'s business is energy I cannot spend on my own recovery."', tags: ['Relationships', 'Focus'] },
  { sub: 'Stay in Your Lane', sum: 'Each of us has a lane — our own life, our own recovery, our own program. When we drift into someone else\'s lane, we create chaos for both of us.', q: '"Staying in my lane is not selfishness. It is the precondition for being any use to anyone else."', tags: ['Relationships', 'Boundaries'] },
  { sub: 'Don\'t Take It Personally', sum: 'Most of what people say and do is about their own experience — not ours. Learning not to personalize other people\'s behavior is one of the most freeing practices in recovery.', q: '"What they said is about them. What I do with it is about me."', tags: ['Relationships', 'Perspective'] },
  { sub: 'Expectations Are Premeditated Resentments', sum: 'Unmet expectations are the breeding ground for resentment. When we hold rigid expectations of others, we are setting up the exact disappointment that will drive us toward anger — or toward a drink.', q: '"Every expectation is an invitation for resentment. Release the expectation, and the resentment loses its fuel."', tags: ['Relationships', 'Resentment'] },
  { sub: 'Resentment Is the Number One Offender', sum: 'More people have been driven back to drinking by resentment than by almost any other force. Holding onto anger is choosing to let someone else rent space in our head for free.', q: '"Resentment is poison we brew ourselves and drink, hoping someone else will suffer."', tags: ['Relationships', 'Resentment'] },
  { sub: 'Love and Tolerance Is Our Code', sum: 'We practice love and tolerance — not just when it is easy, but especially when it is hard. This code keeps us from becoming the very things we resented in others.', q: '"Love and tolerance are not feelings. They are disciplines we choose to practice."', tags: ['Relationships', 'Principles'] },
  { sub: 'To Thine Own Self Be True', sum: 'Recovery asks us to live in alignment with our deepest values — honestly, without pretense or performance. Being true to ourselves is not selfishness. It is integrity.', q: '"The most important person we cannot afford to deceive is ourselves."', tags: ['Relationships', 'Integrity'] },
  // Discipline & Responsibility
  { sub: 'Take Responsibility', sum: 'Recovery begins when we stop blaming circumstances, other people, or our past for where we are. Taking responsibility is not punishment — it is power. It gives us the ability to respond differently.', q: '"As long as I blame someone else, they own my recovery. Taking responsibility gives it back to me."', tags: ['Discipline', 'Accountability'] },
  { sub: 'Do the Work', sum: 'Recovery does not happen by understanding. It happens by doing — working steps, making calls, attending meetings, making amends. Knowledge alone changes nothing. Action changes everything.', q: '"Understanding the program and working the program are two completely different things."', tags: ['Discipline', 'Action'] },
  { sub: 'Show Up', sum: 'The simplest and most powerful practice in recovery. Show up — to the meeting, to the relationship, to the step, to the commitment. Presence is the foundation of everything else.', q: '"Eighty percent of recovery is just showing up when we said we would."', tags: ['Discipline', 'Commitment'] },
  { sub: 'Stay Accountable', sum: 'Accountability to a sponsor, a home group, or a trusted person in recovery is one of the most powerful protections against relapse. Isolation is where relapse grows. Accountability is where recovery grows.', q: '"We stay sober in community. The moment we stop being accountable, we start being alone — and that is where the trouble starts."', tags: ['Discipline', 'Accountability'] },
  { sub: 'No Excuses', sum: 'In recovery, there are always reasons to skip the meeting, the step work, the call. But there are no good excuses. The program works for those who do it — without exception clauses.', q: '"The reason I did not do the work today will not help me tomorrow."', tags: ['Discipline', 'Honesty'] },
  { sub: 'Discipline Equals Freedom', sum: 'The discipline of daily recovery practices — meetings, step work, service, prayer — is not restriction. It is the structure that creates freedom. Without the structure, the chaos returns.', q: '"The discipline of the program is not a cage. It is the frame that holds the life we actually want."', tags: ['Discipline', 'Freedom'] },
  { sub: 'Own Your Recovery', sum: 'No one can work this program for us. Sponsors guide, but they cannot do it. Meetings support, but they cannot do it. Recovery belongs to the person willing to claim it.', q: '"No one else can do this for us. That is both the burden and the gift."', tags: ['Discipline', 'Responsibility'] },
  { sub: 'Clean House', sum: 'Steps 4 through 9 are the cleaning of the house — sorting through the wreckage, making it right, and removing the debris that blocks a new way of living. The house must be cleaned before it can be lived in fully.', q: '"We cannot build a new life on top of the old wreckage. Clean the house first."', tags: ['Discipline', 'Steps'] },
  { sub: 'Trust the Process', sum: 'Recovery does not always look the way we think it should. The steps, the meetings, the sponsors, the service — they work over time, not overnight. Trust the process even when results are not yet visible.', q: '"The work is working even when we cannot see it yet. Trust the process."', tags: ['Discipline', 'Faith'] },
  { sub: 'Work the Steps', sum: 'The twelve steps are the heart of the program — not a suggestion or a metaphor, but a practical path through addiction into a new way of living. The steps work for those who work them.', q: '"We do not work the steps to understand them. We work them to be changed by them."', tags: ['Discipline', 'Steps'] },
  // Relapse Prevention / Sobriety Focus
  { sub: 'No Matter What', sum: 'Sobriety is non-negotiable. No matter what happens — no matter how painful, how unfair, how overwhelming — we do not pick up. No matter what.', q: '"The commitment is not conditional. It is no matter what."', tags: ['Sobriety', 'Commitment'] },
  { sub: 'Just for Today', sum: 'We do not commit to sobriety forever — just for today. This slogan reduces an overwhelming lifetime decision to a single, manageable day. Just today. Just now.', q: '"Just for today I will not drink. Tomorrow is not my problem yet."', tags: ['Sobriety', 'Presence'] },
  { sub: 'Don\'t Pick Up the First Drink', sum: 'The first drink is the dangerous one. Once it is taken, the obsession returns and the craving overtakes rational thinking. The only safe first drink is none.', q: '"If there is no first drink, there is no drunk. That is the only protection that actually works."', tags: ['Sobriety', 'Relapse Prevention'] },
  { sub: 'The First Drink Gets You Drunk', sum: 'For those with addiction, there is no such thing as one controlled drink. The first drink activates a physical craving that rational thinking cannot override. The first is the last safe moment.', q: '"One is too many and a thousand is never enough. That is what makes us different."', tags: ['Sobriety', 'Relapse Prevention'] },
  { sub: 'Play the Tape Through', sum: 'When a drink seems appealing, play the full tape — not just the first moment of relief, but everything that follows: the next day, the next week, the wreckage. Play the whole tape.', q: '"The first scene of the movie always looks good. Play the whole film before you decide."', tags: ['Sobriety', 'Relapse Prevention'] },
  { sub: 'One Is Too Many, a Thousand Never Enough', sum: 'One drink activates a craving that knows no natural stopping point. For those with addiction, there is no controlled amount — only none, or too many.', q: '"The problem is not how many we drink. The problem is what the first one does to us."', tags: ['Sobriety', 'Relapse Prevention'] },
  { sub: 'Avoid People, Places, and Things', sum: 'Early recovery requires vigilance about environments that trigger the obsession. The situations that led us to drink are real threats — not tests to be proven safe.', q: '"We do not have to prove we can handle the bar. We just have to not go in."', tags: ['Sobriety', 'Relapse Prevention'] },
  { sub: 'Keep It Green', sum: 'Staying connected to the pain of the bottom — keeping the memory fresh and real — protects us from the insidious idea that we could drink safely now. Keep the memory green.', q: '"Gratitude and pain are both required. Let neither one fade."', tags: ['Sobriety', 'Gratitude'] },
  { sub: 'Remember Your Last Drunk', sum: 'The mind of addiction edits our memory — removing the suffering and keeping only the relief. Remembering our last drunk honestly is one of the most powerful relapse prevention tools we have.', q: '"We remember the feeling of the first drink. We must also remember how it ended."', tags: ['Sobriety', 'Memory'] },
  { sub: 'Stay Sober', sum: 'Simple, direct, and at the center of everything else. All the slogans, all the steps, all the meetings lead to this: stay sober. Today. One day at a time.', q: '"Everything else we do in recovery is in service of this one thing: staying sober, one day at a time."', tags: ['Sobriety', 'Focus'] },
  // Humility & Perspective
  { sub: 'Stay Humble', sum: 'Humility is not self-deprecation — it is an accurate view of ourselves. In recovery, humility keeps the door open to help, to guidance, and to growth that pride would slam shut.', q: '"Pride closes doors. Humility opens them."', tags: ['Humility', 'Growth'] },
  { sub: 'Let Go of Ego', sum: 'Ego — the need to be right, to be seen, to be in control — is one of the primary obstacles to recovery. Releasing it is not weakness. It is the precondition for genuine spiritual change.', q: '"The ego is not the enemy of the self — but it is often the enemy of recovery."', tags: ['Humility', 'Surrender'] },
  { sub: 'You\'re Not That Important', sum: 'Said with love — the universe does not revolve around us. The people, situations, and outcomes we obsess over are usually not as dependent on us as we believe. Let go a little.', q: '"Most of what we worry about is not actually our responsibility to manage."', tags: ['Humility', 'Perspective'] },
  { sub: 'Principles Over Pride', sum: 'When pride and principles conflict, principles win — in recovery. Pride keeps us from making amends, from asking for help, from admitting we are wrong. Principles carry us forward; pride holds us back.', q: '"Pride has never helped a single person stay sober. Principles have helped millions."', tags: ['Humility', 'Character'] },
  { sub: 'Stay Teachable', sum: 'The moment we decide we know enough is the moment we stop growing. In recovery, remaining open — to feedback, to new understanding, to the experience of others — is a form of protection.', q: '"The most dangerous person in the room is the one who is convinced they already know."', tags: ['Humility', 'Openness'] },
  { sub: 'Remain Willing', sum: 'Willingness is the key that opens every door in recovery. When we lose willingness, we lose access to the help, the steps, and the growth that kept us sober.', q: '"When willingness runs out, everything else runs out too."', tags: ['Humility', 'Willingness'] },
  { sub: 'Keep It Honest', sum: 'Honesty is not just about not lying. It is about being truthful with ourselves about our motives, our fears, our actions. Rigorous honesty is the foundation — without it, nothing else holds.', q: '"Self-deception is the one thing we cannot recover from while we are still doing it."', tags: ['Humility', 'Honesty'] },
  // Gratitude & Positivity
  { sub: 'Gratitude Is the Attitude', sum: 'Gratitude is not a feeling we wait for — it is an attitude we choose to cultivate. A grateful orientation transforms what we have into enough, and often into more than enough.', q: '"Gratitude is not what happens when things go well. It is what keeps things going well."', tags: ['Gratitude', 'Attitude'] },
  { sub: 'Count Your Blessings', sum: 'When self-pity takes hold, this slogan redirects us. List the gifts — sobriety, a new day, the people who stayed, the second chance. Counting blessings crowds out complaint.', q: '"Self-pity and gratitude cannot occupy the same moment. Choose which one gets the space."', tags: ['Gratitude', 'Practice'] },
  { sub: 'Attitude of Gratitude', sum: 'Maintaining gratitude as a daily posture — not just when things go well — is one of the most powerful protections against resentment, self-pity, and the creeping thought that maybe things were better before.', q: '"The attitude of gratitude is armor against almost every threat to our sobriety."', tags: ['Gratitude', 'Practice'] },
  { sub: 'Choose Gratitude', sum: 'Gratitude is a choice — a deliberate redirection of attention from what is wrong to what is right, from what was lost to what was given, from suffering to grace.', q: '"Gratitude is always available. The only question is whether we choose it."', tags: ['Gratitude', 'Choice'] },
  { sub: 'Look for the Good', sum: 'Recovery changes the lens. Instead of cataloguing what is wrong with people, situations, and ourselves, we train ourselves to find the good — not because nothing is wrong, but because the good is also real.', q: '"Whatever we look for, we tend to find. We might as well look for the good."', tags: ['Gratitude', 'Perspective'] },
  { sub: 'Service Keeps You Sober', sum: 'Getting outside ourselves and helping another person is one of the most reliable protections against relapse. Service takes us out of our own heads and into something larger than our own problems.', q: '"The fastest way out of our own suffering is to walk into someone else\'s and try to help."', tags: ['Gratitude', 'Service'] },
  // Service & Fellowship
  { sub: 'You Can\'t Keep It Unless You Give It Away', sum: 'Recovery is not something we accumulate — it is something we circulate. The act of sharing our experience, strength, and hope with another person is what keeps our own recovery alive.', q: '"We stay sober by helping others get sober. That is not generosity — it is necessity."', tags: ['Service', 'Fellowship'] },
  { sub: 'We Keep What We Have by Giving It Away', sum: 'The counterintuitive truth of recovery: the more freely we share what we have received, the more we retain it. Hoarding sobriety leads to losing it. Giving it away deepens it.', q: '"Recovery grows when it is shared. It stagnates when it is kept."', tags: ['Service', 'Fellowship'] },
  { sub: 'Carry the Message', sum: 'Step 12 asks us to carry the message — not the person, not our opinions, but the message of hope and change that we ourselves received. That message is the most important thing we can pass on.', q: '"The message is not ours — we are just the messengers. Carry it faithfully."', tags: ['Service', 'Step 12'] },
  { sub: 'Help Others', sum: 'The simplest expression of Step 12. When we do not know what to do, when we feel lost or purposeless, this direction cuts through all of it: find someone to help.', q: '"When in doubt about what to do next — help someone."', tags: ['Service', 'Action'] },
  { sub: 'Stay Connected', sum: 'Isolation is where relapse grows. Connection — to the fellowship, to a sponsor, to recovery friends — is where sobriety lives. We cannot stay sober in isolation, and we do not have to.', q: '"We are only as sick as our secrets and as safe as our connections."', tags: ['Service', 'Fellowship'] },
  { sub: 'Fellowship Is the Key', sum: 'The support of others who have walked the same path is irreplaceable. Fellowship is not a supplement to the program — it is a core part of it. We recover together.', q: '"No one recovers alone. Fellowship is not optional — it is the program."', tags: ['Service', 'Fellowship'] },
  { sub: 'Together We Recover', sum: 'Recovery is not a solo journey. The fellowship exists because going it alone has never worked for most of us. Together — with shared experience, mutual support, and honest accountability — we recover.', q: '"The road is hard alone. Together, it is still hard — but it is not walked alone."', tags: ['Service', 'Unity'] },
  { sub: 'Unity, Service, Recovery', sum: 'The three legacies of the fellowship. Unity keeps the group intact. Service keeps recovery circulating. Recovery is the result that makes the rest worthwhile. All three are required.', q: '"Remove any one of the three legacies and the whole structure weakens. All three are needed."', tags: ['Service', 'Traditions'] },
  // Short / Daily Use
  { sub: 'Stay the Course', sum: 'There will be days when recovery feels pointless, slow, or unrewarding. Stay the course. The path works — not on our timeline, but on one that serves our actual growth.', q: '"The results of staying the course are rarely visible in the moment. They show up later, and they are worth it."', tags: ['Daily Use', 'Perseverance'] },
  { sub: 'Keep Going', sum: 'When it gets hard — and it will get hard — this is the instruction: keep going. Not perfectly. Not joyfully. Just forward. One more day. One more meeting. One more right choice.', q: '"Keep going. The only exit from recovery is the one that leads back to where we started."', tags: ['Daily Use', 'Persistence'] },
  { sub: 'Stay Present', sum: 'Presence is both the simplest and the hardest practice in recovery. The pull of past regret and future fear is constant. Stay present. Everything we need is here, in this moment.', q: '"The present moment is the only moment recovery is actually possible."', tags: ['Daily Use', 'Mindfulness'] },
  { sub: 'Choose Peace', sum: 'Peace is available to us in almost every moment — but only if we choose it. Peace does not come from circumstances changing. It comes from changing how we respond to circumstances.', q: '"Peace is not what happens when things go right. It is what we choose even when they do not."', tags: ['Daily Use', 'Serenity'] },
  { sub: 'Just Breathe', sum: 'Before the next thought, the next reaction, the next decision — breathe. The breath is always available as an anchor back to the present moment and away from panic or impulse.', q: '"One breath. Just one. That is where recovery lives — in the pause between stimulus and response."', tags: ['Daily Use', 'Presence'] },
  { sub: 'Stay Grounded', sum: 'When anxiety spins us upward into catastrophic thinking, grounding brings us back. A routine, a meeting, a step, a call to a sponsor — whatever brings us back to solid ground.', q: '"Grounded people do not tend to relapse. The work of staying grounded is the work of staying sober."', tags: ['Daily Use', 'Stability'] },
  // Modern Recovery Sayings
  { sub: 'Progress Over Perfection', sum: 'The destination is growth, not flawlessness. Every honest effort — even an imperfect one — is a step in the right direction. Progress is the measure. Perfection is the trap.', q: '"Done imperfectly is infinitely better than perfect but never started."', tags: ['Modern', 'Growth'] },
  { sub: 'Peace Over Chaos', sum: 'Recovery is, at its heart, a move from chaos toward peace. When we face a choice between our old reactive patterns and a calmer response, we choose peace — deliberately, repeatedly.', q: '"Every time we choose peace over chaos, we are voting for the life we actually want."', tags: ['Modern', 'Serenity'] },
  { sub: 'One Step at a Time', sum: 'The whole path does not need to be visible. The next step does. Recovery asks us to take the step that is in front of us — not the one three miles down the road.', q: '"We do not have to see the destination. We just have to take the step that is right in front of us."', tags: ['Modern', 'Presence'] },
  { sub: 'Slow Down', sum: 'The urgency that drove our addiction — the need to feel better now, to have answers now, to fix it now — is itself a pattern to be examined. Slowing down is often the most radical act in recovery.', q: '"Most of our worst decisions were made in a hurry. Slow down."', tags: ['Modern', 'Patience'] },
  { sub: 'Keep Showing Up', sum: 'Not every meeting will be transformative. Not every day will feel meaningful. But showing up consistently — when it matters least — is what makes it possible to show up when it matters most.', q: '"The meeting that changes your life might be the one you almost did not go to."', tags: ['Modern', 'Commitment'] },
  // Big Book / Literature-Derived
  { sub: 'Acceptance Is the Answer to All My Problems Today', sum: 'One of the most quoted passages in recovery literature. In every situation, acceptance — not approval, but acknowledgment of reality — is the beginning of peace and the end of fighting what is.', q: '"I cannot change what I refuse to accept. And I cannot accept what I am still pretending is not real."', tags: ['Literature', 'Acceptance'] },
  { sub: 'Resentment Is the Number One Offender', sum: 'The literature is unambiguous: more people have returned to drinking over resentment than almost any other cause. Holding onto anger is self-destruction disguised as righteousness.', q: '"Resentment is a poison we brew ourselves and drink, hoping someone else suffers."', tags: ['Literature', 'Resentment'] },
  { sub: 'Selfishness — Self-Centeredness! That Is the Root of Our Troubles', sum: 'The driving force behind most of our destructive behavior is self-centered fear and desire. Recovery is, at its core, a gradual movement from self-centeredness toward something larger than ourselves.', q: '"The program asks us to become less self-centered — not as punishment, but as the only way to actually become happy."', tags: ['Literature', 'Character'] },
  { sub: 'We Are Not Saints', sum: 'Recovery does not demand perfection or sainthood — only progress, honesty, and willingness to keep trying. The program is for those who want it, not those who are already perfect.', q: '"We are not saints — we are people trying to get better, one honest day at a time."', tags: ['Literature', 'Self-Compassion'] },
  { sub: 'We Claim Spiritual Progress Rather Than Spiritual Perfection', sum: 'The standard in recovery is not perfect — it is improving. Spiritual progress is real, measurable, and sufficient. We do not have to be spiritually complete to stay sober and to grow.', q: '"Progress is what we claim. Perfection is what we release."', tags: ['Literature', 'Growth'] },
  { sub: 'Our Primary Purpose Is to Stay Sober and Help Other Alcoholics', sum: 'When we lose our way, this is the anchor. The primary purpose is not comfort, not success, not approval — it is to stay sober and to help others do the same. Everything else is secondary.', q: '"When I forget my purpose, I read this again. Staying sober and helping others — that is the whole job."', tags: ['Literature', 'Purpose'] },
  // Expanded / Meeting Phrases
  { sub: 'Feel It, Deal It, Heal It', sum: 'Numbing feelings was the old way. Recovery asks us to feel them fully, process them honestly, and then heal — not around the pain, but through it. All three steps are required.', q: '"We cannot heal what we refuse to feel."', tags: ['Expanded', 'Emotional Sobriety'] },
  { sub: 'Move a Muscle, Change a Thought', sum: 'When stuck in a spiral of anxious or negative thinking, physical action can break the pattern. Get up, go for a walk, call someone — move. The thought changes when the body moves.', q: '"Thinking our way out of a thought is harder than moving our way out of it."', tags: ['Expanded', 'Action'] },
  { sub: 'When in Doubt, Don\'t', sum: 'If you are not sure whether an action aligns with recovery, that doubt is information. When in doubt, don\'t. The doubt is often the healthiest part of us speaking up first.', q: '"The doubt that slows us down is often the wisdom we do not yet have words for."', tags: ['Expanded', 'Discernment'] },
  { sub: 'Do What\'s in Front of You', sum: 'Stop looking for the grand plan. Stop waiting for the perfect moment or the full picture. Do the thing that is right in front of you. That is enough. That is the work.', q: '"The task in front of us is usually the only task that matters right now."', tags: ['Expanded', 'Presence'] },
  { sub: 'Keep the Plug in the Jug', sum: 'One of the most direct and practical slogans in the fellowship — a concrete, literal reminder of the most important commitment we make each day.', q: '"Everything else we talk about in recovery depends on this one staying true."', tags: ['Expanded', 'Sobriety'] },
  { sub: 'Don\'t React — Respond', sum: 'Reaction is automatic, driven by emotion. Response is deliberate, guided by values and recovery principles. The practice of choosing a response rather than defaulting to a reaction is the heart of emotional sobriety.', q: '"Between stimulus and response is a space. In that space is our power."', tags: ['Expanded', 'Emotional Sobriety'] },
  { sub: 'Pause, Pray, Proceed', sum: 'Before acting in a charged moment — pause to create space, pray to seek guidance, then proceed with intention. These three words are a complete decision-making process in recovery.', q: '"Three steps: pause, pray, proceed. Everything we need is in those three."', tags: ['Expanded', 'Spiritual'] },
  { sub: 'Stay Willing', sum: 'Willingness is the hinge on which recovery swings. When willingness is present, doors open. When it disappears, everything closes. Protect willingness as the most essential resource in the program.', q: '"The only thing required at every step is willingness. When it runs out, ask for more."', tags: ['Expanded', 'Willingness'] },
  { sub: 'Keep It Real', sum: 'Authenticity — in meetings, in step work, in relationships — is both protection and medicine. Pretending to be fine when we are not, or performing recovery rather than living it, keeps us sick.', q: '"The rooms work because people tell the truth in them. Keep it real."', tags: ['Expanded', 'Honesty'] },
  { sub: 'H.A.L.T.', sum: 'Before making any important decision or reacting to a strong feeling, check these four: Hungry, Angry, Lonely, Tired. These four states are the most common triggers for poor decisions and relapse.', q: '"Before doing anything significant — check HALT. Most bad decisions fail at least one of those four."', tags: ['Expanded', 'Self-Care'] },
];

